const raw = $input.first().json;
const body = raw.body || raw;
const message = String(body.message || '').trim();
const business_id = String(body.business_id || '').trim();
const session_id = String(body.session_id || Date.now()).trim();

if (!message || !business_id) {
  return [{ json: { valid: false, error: 'message and business_id required' } }];
}

const q = message.toLowerCase();
const now = new Date();

const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0, 0);
const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59, 999);

let dateFrom, dateTo, period, intentLabel;

// --- TODAY ---
if (q.includes('today') || q.includes('aaj') || q.includes('آج')) {
  period = 'today'; intentLabel = 'Aaj ki sales';
  dateFrom = new Date(todayStart); dateTo = new Date(todayEnd);
}
// --- YESTERDAY ---
else if (q.includes('yesterday') || q.includes('kal') || q.includes('کل')) {
  period = 'yesterday'; intentLabel = 'Kal ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 1);
  dateTo = new Date(todayEnd); dateTo.setDate(dateTo.getDate() - 1);
}
// --- LAST 90 DAYS / 3 MONTHS ---
else if (
  q.includes('90 day') || q.includes('90 din') || q.includes('90din') ||
  q.includes('teen mahine') || q.includes('3 month') || q.includes('tin month') ||
  q.includes('last quarter') || q.includes('pichle teen')
) {
  period = '90days'; intentLabel = 'Pichle 90 din ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 90);
  dateTo = new Date(todayEnd);
}
// --- LAST 30 DAYS ---
else if (
  q.includes('30 day') || q.includes('30 din') || q.includes('pichle 30')
) {
  period = '30days'; intentLabel = 'Pichle 30 din ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 30);
  dateTo = new Date(todayEnd);
}
// --- SPECIFIC MONTH BY NAME (e.g. february, january, march) ---
else if (
  q.match(/\b(january|february|march|april|may|june|july|august|september|october|november|december)\b/) ||
  q.match(/\b(jan|feb|mar|apr|jun|jul|aug|sep|oct|nov|dec)\b/) ||
  q.match(/\b(january|february|march|april|may|june|july|august|september|october|november|december)\s+\d{4}\b/)
) {
  const monthNames = ['january','february','march','april','may','june','july','august','september','october','november','december'];
  const shortNames = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];
  let monthIdx = -1;
  for (let i = 0; i < monthNames.length; i++) {
    if (q.includes(monthNames[i]) || q.includes(shortNames[i])) { monthIdx = i; break; }
  }
  // Detect year from query, else use current or previous year smartly
  const yearMatch = q.match(/\b(20\d{2})\b/);
  let targetYear = yearMatch ? parseInt(yearMatch[1]) : now.getFullYear();
  // If month is in future this year, go to last year
  if (monthIdx > now.getMonth() && targetYear === now.getFullYear()) targetYear -= 1;
  period = 'specific_month'; intentLabel = `${monthNames[monthIdx] ? monthNames[monthIdx].charAt(0).toUpperCase() + monthNames[monthIdx].slice(1) : 'Month'} ${targetYear} ki sales`;
  dateFrom = new Date(targetYear, monthIdx, 1, 0, 0, 0, 0);
  dateTo = new Date(targetYear, monthIdx + 1, 0, 23, 59, 59, 999);
}
// --- LAST MONTH ---
else if (q.includes('last month') || q.includes('pichle mahine') || q.includes('pichla mahina') || q.includes('pichle mah')) {
  period = 'last_month'; intentLabel = 'Pichle mahine ki sales';
  dateFrom = new Date(now.getFullYear(), now.getMonth() - 1, 1, 0, 0, 0, 0);
  dateTo = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59, 999);
}
// --- THIS MONTH ---
else if (q.includes('month') || q.includes('mahina') || q.includes('mahine') || q.includes('mah ')) {
  period = 'month'; intentLabel = 'Is mahine ki sales';
  dateFrom = new Date(now.getFullYear(), now.getMonth(), 1, 0, 0, 0, 0);
  dateTo = new Date(todayEnd);
}
// --- LAST WEEK ---
else if (q.includes('last week') || q.includes('pichle hafte') || q.includes('pichla hafta')) {
  period = 'last_week'; intentLabel = 'Pichle hafte ki sales';
  const dayOfWeek = now.getDay();
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - dayOfWeek - 7);
  dateTo = new Date(todayStart); dateTo.setDate(dateTo.getDate() - dayOfWeek - 1); dateTo.setHours(23,59,59,999);
}
// --- THIS WEEK ---
else if (q.includes('week') || q.includes('hafta') || q.includes('hafte') || q.includes('ہفتہ')) {
  period = 'week'; intentLabel = 'Is hafte ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 7);
  dateTo = new Date(todayEnd);
}
// --- THIS YEAR ---
else if (q.includes('year') || q.includes('saal') || q.includes('سال')) {
  period = 'year'; intentLabel = 'Is saal ki sales';
  dateFrom = new Date(now.getFullYear(), 0, 1, 0, 0, 0, 0);
  dateTo = new Date(todayEnd);
}
// --- DEFAULT: last 7 days ---
else {
  period = 'week'; intentLabel = 'Is hafte ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 7);
  dateTo = new Date(todayEnd);
}

const dateFromISO = dateFrom.toISOString();
const dateToISO = dateTo.toISOString();

const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imliemx5a3FndWlxYnd2a2JxcmF1Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzAwOTk0MDcsImV4cCI6MjA4NTY3NTQwN30.qnV96DNAZ8_9KQ9xbyOQrjbr6z-amBtebPn3rBM_kRw';
const base = 'https://ibzlykqguiqbwvkbqrau.supabase.co/rest/v1/woocommerce_orders';
const fields = 'wc_order_id,order_number,status,total,customer_name,date_created,line_items';
const ordersUrl = `${base}?business_id=eq.${business_id}&date_created=gte.${dateFromISO}&date_created=lte.${dateToISO}&select=${fields}&order=date_created.desc&limit=500`;

return [{
  json: { valid: true, message, business_id, session_id, period, intentLabel, dateFrom: dateFromISO, dateTo: dateToISO, ordersUrl, supaKey: SUPA_KEY, q }
}];

const classifyData = $('Classify & Build Query').first().json;
const rawInput = $input.all();

let orders = [];
for (const item of rawInput) {
  const d = item.json;
  if (Array.isArray(d)) {
    orders = orders.concat(d);
  } else if (d && d.wc_order_id) {
    orders.push(d);
  } else if (d && Array.isArray(d.data)) {
    orders = orders.concat(d.data);
  }
}

if (orders.length === 0) {
  return [{
    json: {
      ...classifyData,
      summary: `${classifyData.intentLabel} mein koi order nahi mila. (${classifyData.dateFrom.split('T')[0]} se ${classifyData.dateTo.split('T')[0]} tak)`,
      total_orders: 0,
      total_revenue: 0,
      analytics: null,
      dailyBreakdown: []
    }
  }];
}

let totalRevenue = 0, completedRevenue = 0, pendingRevenue = 0;
const statusCount = {}, productSales = {}, dailyRevenue = {};

for (const o of orders) {
  const amount = parseFloat(o.total) || 0;
  totalRevenue += amount;
  const status = o.status || 'unknown';
  statusCount[status] = (statusCount[status] || 0) + 1;
  if (['completed', 'processing'].includes(status)) completedRevenue += amount;
  else if (status === 'pending') pendingRevenue += amount;

  if (o.date_created) {
    const day = o.date_created.split('T')[0] || o.date_created.split(' ')[0];
    if (!dailyRevenue[day]) dailyRevenue[day] = { revenue: 0, orders: 0 };
    dailyRevenue[day].revenue += amount;
    dailyRevenue[day].orders += 1;
  }

  const lineItems = Array.isArray(o.line_items) ? o.line_items : [];
  for (const item of lineItems) {
    const name = item.name || 'Unknown';
    const qty = parseInt(item.quantity) || 1;
    const subtotal = parseFloat(item.subtotal) || 0;
    if (!productSales[name]) productSales[name] = { qty: 0, revenue: 0 };
    productSales[name].qty += qty;
    productSales[name].revenue += subtotal;
  }
}

const topProducts = Object.entries(productSales)
  .sort((a, b) => b[1].revenue - a[1].revenue).slice(0, 5)
  .map(([name, data]) => `• ${name}: Rs.${Math.round(data.revenue).toLocaleString()} (${data.qty} units)`);

const statusLines = Object.entries(statusCount)
  .sort((a, b) => b[1] - a[1]).map(([s, c]) => `${s}: ${c}`);

const avgOrderValue = Math.round(totalRevenue / orders.length);

// Sort daily revenue
const sortedDays = Object.entries(dailyRevenue).sort((a, b) => b[1].revenue - a[1].revenue);
const bestDay = sortedDays[0];
const worstDay = sortedDays[sortedDays.length - 1];

// Build top 10 days breakdown for date-specific queries
const top10Days = sortedDays.slice(0, 10)
  .map(([date, data]) => `• ${date}: Rs.${Math.round(data.revenue).toLocaleString()} (${data.orders} orders)`);

const summary = `${classifyData.intentLabel} (${classifyData.dateFrom.split('T')[0]} se ${classifyData.dateTo.split('T')[0]} tak):

Total Orders: ${orders.length}
Total Revenue: Rs.${Math.round(totalRevenue).toLocaleString()}
Completed Revenue: Rs.${Math.round(completedRevenue).toLocaleString()}
Pending Revenue: Rs.${Math.round(pendingRevenue).toLocaleString()}
Average Order Value: Rs.${avgOrderValue.toLocaleString()}
Order Status: ${statusLines.join(', ')}
${topProducts.length > 0 ? `\nTop Products:\n${topProducts.join('\n')}` : ''}
${bestDay ? `\nBest Day: ${bestDay[0]} — Rs.${Math.round(bestDay[1].revenue).toLocaleString()} (${bestDay[1].orders} orders)` : ''}
${worstDay && worstDay[0] !== bestDay[0] ? `Lowest Day: ${worstDay[0]} — Rs.${Math.round(worstDay[1].revenue).toLocaleString()}` : ''}
\nTop 10 Highest Revenue Dates:\n${top10Days.join('\n')}`.trim();

return [{
  json: {
    ...classifyData,
    summary,
    total_orders: orders.length,
    total_revenue: Math.round(totalRevenue),
    analytics: {
      totalRevenue: Math.round(totalRevenue),
      completedRevenue: Math.round(completedRevenue),
      pendingRevenue: Math.round(pendingRevenue),
      avgOrderValue,
      statusCount,
      topProducts,
      bestDay: bestDay ? bestDay[0] : null,
      top10Days
    }
  }
}];

const openaiResp = $input.first().json;
const analyticsData = $('Calculate Analytics').first().json;
const classifyData = $('Classify & Build Query').first().json;

const responseTimeMs = Date.now() - parseInt(classifyData.session_id);

let reply = '';
try {
  if (openaiResp.message && openaiResp.message.content) {
    reply = openaiResp.message.content;
  } else if (openaiResp.text) {
    reply = openaiResp.text;
  } else {
    reply = analyticsData.summary || 'Data fetch ho gaya lekin AI response nahi aaya.';
  }
} catch(e) {
  reply = analyticsData.summary || 'Error occurred.';
}

return [{
  json: {
    success: true,
    reply,
    period: classifyData.period,
    total_orders: analyticsData.total_orders,
    total_revenue: analyticsData.total_revenue,
    session_id: classifyData.session_id,
    logEntry: {
      business_id: classifyData.business_id,
      workflow_type: 'sales_analytics',
      query_text: classifyData.message.substring(0, 500),
      intent: classifyData.period,
      response_time_ms: responseTimeMs > 0 ? responseTimeMs : 3000,
      success: true,
      created_at: new Date().toISOString()
    }
  }
}];
